function solve(m: number, n: number, waitCost: number[][]): number {
    // Directions: right (0, 1), down (1, 0)
    const dirs = [[0, 1], [1, 0]];

    // Initialize a 2D array to store the minimum cost to reach each cell
    // We use a 2D array of size (m x n) to store the minimum cost
    const dp: number[][] = new Array(m).fill(null).map(() => new Array(n).fill(Infinity));

    // Starting at (0, 0), the cost is the entry cost
    dp[0][0] = (0 + 1) * (0 + 1);

    // Use a priority queue to perform Dijkstra's algorithm
    // Each element in the queue is [currentCost, row, col, time]
    const pq = new PriorityQueue<[number, number, number, number]>();
    pq.enqueue([dp[0][0], 0, 0, 1]); // time starts at 1

    while (!pq.isEmpty()) {
        const [cost, row, col, time] = pq.dequeue();

        // If we have reached the destination, return the cost
        if (row === m - 1 && col === n - 1) {
            return cost;
        }

        // If the current time is odd, we can move right or down
        if (time % 2 === 1) {
            for (const [dr, dc] of dirs) {
                const newRow = row + dr;
                const newCol = col + dc;

                // Check if the new position is valid
                if (newRow >= 0 && newRow < m && newCol >= 0 && newCol < n) {
                    const newTime = time + 1;
                    const newCost = cost + (newRow + 1) * (newCol + 1);

                    if (newCost < dp[newRow][newCol]) {
                        dp[newRow][newCol] = newCost;
                        pq.enqueue([newCost, newRow, newCol, newTime]);
                    }
                }
            }
        } 
        // If the current time is even, we must wait
        else {
            const newTime = time + 1;
            const newCost = cost + waitCost[row][col];

            if (newCost < dp[row][col]) {
                dp[row][col] = newCost;
                pq.enqueue([newCost, row, col, newTime]);
            }
        }
    }

    // If we reach here, no path was found (should not happen in valid inputs)
    return -1;
}

